'use client';

import Image from 'next/image';
import { Card } from '@/components/ui/card';

interface Emoticon {
  id: string;
  name: string;
  image_url: string;
}

interface EmoticonPickerProps {
  emoticons: Emoticon[];
  onSelect: (emoticon: Emoticon) => void;
  onClose: () => void;
}

export function EmoticonPicker({
  emoticons,
  onSelect,
  onClose,
}: EmoticonPickerProps) {
  return (
    <>
      {/* Backdrop */}
      <div
        className="fixed inset-0 z-40"
        onClick={onClose}
      />
      
      {/* Picker */}
      <Card className="absolute bottom-12 right-0 z-50 w-64 p-3 shadow-lg border border-border">
        <div className="grid grid-cols-5 gap-2">
          {emoticons.map((emoticon) => (
            <button
              key={emoticon.id}
              type="button"
              onClick={() => onSelect(emoticon)}
              className="w-10 h-10 p-1 hover:bg-muted transition-colors flex items-center justify-center"
              title={`:${emoticon.name}:`}
            >
              <Image
                src={emoticon.image_url}
                alt={emoticon.name}
                width={28}
                height={28}
                className="object-contain"
              />
            </button>
          ))}
        </div>
        {emoticons.length === 0 && (
          <p className="text-sm text-muted-foreground text-center py-4">
            등록된 이모티콘이 없습니다.
          </p>
        )}
      </Card>
    </>
  );
}
