'use client';

import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '@/components/auth-provider';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Send, MessageSquare, Settings, Smile } from 'lucide-react';
import { EmoticonManagerModal } from '@/components/emoticon-manager-modal';
import { EmoticonPicker } from '@/components/emoticon-picker';
import { toast } from 'sonner';
import Image from 'next/image';

interface GuestbookEntry {
  id: string;
  author: string;
  content: string;
  created_at: string;
}

interface Emoticon {
  id: string;
  name: string;
  image_url: string;
}

export function GuestBookSection() {
  const { hasPermission } = useAuth();

  const [entries, setEntries] = useState<GuestbookEntry[]>([]);
  const [emoticons, setEmoticons] = useState<Emoticon[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [author, setAuthor] = useState('');
  const [content, setContent] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [showEmoticonManager, setShowEmoticonManager] = useState(false);
  const [showEmoticonPicker, setShowEmoticonPicker] = useState(false);

  const fetchEntries = useCallback(async () => {
    try {
      const res = await fetch('/api/guestbook');
      if (res.ok) {
        const data = await res.json();
        setEntries(data);
      }
    } catch (error) {
      console.error('Failed to fetch entries:', error);
    } finally {
      setIsLoading(false);
    }
  }, []);

  const fetchEmoticons = useCallback(async () => {
    try {
      const res = await fetch('/api/emoticons');
      if (res.ok) {
        const data = await res.json();
        setEmoticons(data);
      }
    } catch (error) {
      console.error('Failed to fetch emoticons:', error);
    }
  }, []);

  useEffect(() => {
    fetchEntries();
    fetchEmoticons();
  }, [fetchEntries, fetchEmoticons]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (!author.trim() || !content.trim()) {
      toast.error('이름과 내용을 모두 입력해주세요.');
      return;
    }

    setIsSubmitting(true);
    try {
      const res = await fetch('/api/guestbook', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ author, content }),
      });

      if (res.ok) {
        setContent('');
        fetchEntries();
        toast.success('방명록이 등록되었습니다.');
      } else {
        toast.error('등록에 실패했습니다.');
      }
    } catch {
      toast.error('등록 중 오류가 발생했습니다.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleManageEmoticons = () => {
    if (!hasPermission(['SUPER_ADMIN'])) return;
    setShowEmoticonManager(true);
  };

  const handleEmoticonSelect = (emoticon: Emoticon) => {
    setContent((prev) => prev + ` :${emoticon.name}: `);
    setShowEmoticonPicker(false);
  };

  const formatDate = (dateString: string) => {
    return new Date(dateString).toLocaleDateString('ko-KR', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  };

  const renderContentWithEmoticons = (text: string) => {
    const emoticonRegex = /:([a-zA-Z0-9_]+):/g;
    const parts = text.split(emoticonRegex);
    
    return parts.map((part, index) => {
      if (index % 2 === 1) {
        const emoticon = emoticons.find((e) => e.name === part);
        if (emoticon) {
          return (
            <span key={index} className="inline-block align-middle mx-1">
              <Image
                src={emoticon.image_url}
                alt={emoticon.name}
                width={24}
                height={24}
                className="inline-block"
              />
            </span>
          );
        }
        return `:${part}:`;
      }
      return part;
    });
  };

  if (isLoading) {
    return (
      <div className="space-y-4">
        <Card className="p-6 border-0 shadow-none bg-card/70 backdrop-blur-sm">
          <div className="space-y-4">
            <div className="h-10 bg-muted animate-pulse" />
            <div className="h-24 bg-muted animate-pulse" />
          </div>
        </Card>
        {[...Array(3)].map((_, i) => (
          <Card key={i} className="p-4 border-0 shadow-none bg-card/70 backdrop-blur-sm">
            <div className="space-y-2">
              <div className="h-4 bg-muted animate-pulse w-1/4" />
              <div className="h-4 bg-muted animate-pulse w-full" />
            </div>
          </Card>
        ))}
      </div>
    );
  }

  return (
    <>
      {/* Write Form */}
      <Card className="mb-8 border-0 shadow-none bg-card/70 backdrop-blur-sm">
        <CardContent className="p-6">
          <div className="flex items-center justify-between mb-4">
            <h2 className="text-lg font-medium">방명록 작성</h2>
            <Button
              variant="outline"
              size="sm"
              onClick={handleManageEmoticons}
              className="flex items-center gap-2"
            >
              <Settings className="h-4 w-4" />
              이모티콘 관리
            </Button>
          </div>
          <form onSubmit={handleSubmit} className="space-y-4">
            <Input
              placeholder="이름"
              value={author}
              onChange={(e) => setAuthor(e.target.value)}
            />
            <div className="relative">
              <Textarea
                placeholder="메시지를 입력하세요..."
                value={content}
                onChange={(e) => setContent(e.target.value)}
                className="min-h-[100px] pr-12"
              />
              {emoticons.length > 0 && (
                <Button
                  type="button"
                  variant="ghost"
                  size="icon"
                  className="absolute bottom-2 right-2"
                  onClick={() => setShowEmoticonPicker(!showEmoticonPicker)}
                >
                  <Smile className="h-5 w-5 text-muted-foreground" />
                </Button>
              )}
              {showEmoticonPicker && (
                <EmoticonPicker
                  emoticons={emoticons}
                  onSelect={handleEmoticonSelect}
                  onClose={() => setShowEmoticonPicker(false)}
                />
              )}
            </div>
            <div className="flex justify-end">
              <Button type="submit" disabled={isSubmitting} className="flex items-center gap-2">
                <Send className="h-4 w-4" />
                {isSubmitting ? '등록 중...' : '등록'}
              </Button>
            </div>
          </form>
        </CardContent>
      </Card>

      {/* Entries List */}
      {entries.length === 0 ? (
        <Card className="p-12 text-center border-0 shadow-none bg-card/70 backdrop-blur-sm">
          <div className="flex flex-col items-center gap-4 text-muted-foreground">
            <MessageSquare className="h-12 w-12" />
            <p>아직 방명록이 없습니다.</p>
            <p className="text-sm">첫 번째 방명록을 남겨보세요!</p>
          </div>
        </Card>
      ) : (
        <div className="space-y-4">
          {entries.map((entry) => (
            <Card key={entry.id} className="border-0 shadow-none bg-card/70 backdrop-blur-sm">
              <CardContent className="p-4">
                <div className="flex justify-between items-start mb-2">
                  <span className="font-medium text-foreground">{entry.author}</span>
                  <span className="text-xs text-muted-foreground">
                    {formatDate(entry.created_at)}
                  </span>
                </div>
                <p className="text-foreground leading-relaxed">
                  {renderContentWithEmoticons(entry.content)}
                </p>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      

      <EmoticonManagerModal
        open={showEmoticonManager}
        onOpenChange={setShowEmoticonManager}
        onUpdate={fetchEmoticons}
      />
    </>
  );
}
