'use client';

import { useState, useEffect, useCallback } from 'react';
import Image from 'next/image';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { Plus, Trash2, Upload } from 'lucide-react';
import { toast } from 'sonner';

interface Emoticon {
  id: string;
  name: string;
  image_url: string;
}

interface EmoticonManagerModalProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onUpdate: () => void;
}

export function EmoticonManagerModal({
  open,
  onOpenChange,
  onUpdate,
}: EmoticonManagerModalProps) {
  const [emoticons, setEmoticons] = useState<Emoticon[]>([]);
  const [newName, setNewName] = useState('');
  const [newImageFile, setNewImageFile] = useState<File | null>(null);
  const [newImagePreview, setNewImagePreview] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  const fetchEmoticons = useCallback(async () => {
    try {
      const res = await fetch('/api/emoticons');
      if (res.ok) {
        const data = await res.json();
        setEmoticons(data);
      }
    } catch (error) {
      console.error('Failed to fetch emoticons:', error);
    }
  }, []);

  useEffect(() => {
    if (open) {
      fetchEmoticons();
    }
  }, [open, fetchEmoticons]);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setNewImageFile(file);
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleAdd = async () => {
    if (!newName.trim() || !newImageFile) {
      toast.error('이름과 이미지를 모두 입력해주세요.');
      return;
    }

    // Validate name format (alphanumeric and underscore only)
    if (!/^[a-zA-Z0-9_]+$/.test(newName)) {
      toast.error('이름은 영문, 숫자, 밑줄(_)만 사용할 수 있습니다.');
      return;
    }

    setIsLoading(true);
    try {
      const formData = new FormData();
      formData.append('name', newName);
      formData.append('image', newImageFile);

      const res = await fetch('/api/emoticons', {
        method: 'POST',
        body: formData,
      });

      if (res.ok) {
        toast.success('이모티콘이 추가되었습니다.');
        setNewName('');
        setNewImageFile(null);
        setNewImagePreview(null);
        fetchEmoticons();
        onUpdate();
      } else {
        const error = await res.json();
        toast.error(error.error || '추가에 실패했습니다.');
      }
    } catch {
      toast.error('추가 중 오류가 발생했습니다.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    try {
      const res = await fetch(`/api/emoticons/${id}`, {
        method: 'DELETE',
      });

      if (res.ok) {
        toast.success('이모티콘이 삭제되었습니다.');
        fetchEmoticons();
        onUpdate();
      } else {
        toast.error('삭제에 실패했습니다.');
      }
    } catch {
      toast.error('삭제 중 오류가 발생했습니다.');
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-lg max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>이모티콘 관리</DialogTitle>
          <DialogDescription>이모티콘을 추가하거나 삭제하세요.</DialogDescription>
        </DialogHeader>
        
        <div className="space-y-6">
          {/* Add New Emoticon */}
          <div className="space-y-4 p-4 bg-muted">
            <h3 className="font-medium">새 이모티콘 추가</h3>
            <div className="space-y-3">
              <div className="space-y-2">
                <Label htmlFor="emoticon-name">이름 (영문, 숫자, 밑줄만)</Label>
                <Input
                  id="emoticon-name"
                  value={newName}
                  onChange={(e) => setNewName(e.target.value)}
                  placeholder="예: happy_face"
                />
              </div>
              
              <div className="space-y-2">
                <Label>이미지</Label>
                <div className="flex items-center gap-4">
                  {newImagePreview ? (
                    <div className="w-12 h-12 relative bg-card border border-border">
                      <Image
                        src={newImagePreview}
                        alt="Preview"
                        fill
                        className="object-contain"
                      />
                    </div>
                  ) : (
                    <div className="w-12 h-12 bg-card border border-border flex items-center justify-center">
                      <Plus className="h-4 w-4 text-muted-foreground" />
                    </div>
                  )}
                  <label className="flex-1">
                    <div className="flex items-center justify-center gap-2 px-4 py-2 bg-secondary text-secondary-foreground cursor-pointer hover:bg-primary hover:text-primary-foreground transition-colors">
                      <Upload className="h-4 w-4" />
                      이미지 선택
                    </div>
                    <input
                      type="file"
                      accept="image/*"
                      onChange={handleImageChange}
                      className="hidden"
                    />
                  </label>
                </div>
              </div>

              <Button
                onClick={handleAdd}
                disabled={isLoading || !newName || !newImageFile}
                className="w-full"
              >
                <Plus className="h-4 w-4 mr-2" />
                {isLoading ? '추가 중...' : '추가'}
              </Button>
            </div>
          </div>

          {/* Emoticon List */}
          <div className="space-y-3">
            <h3 className="font-medium">등록된 이모티콘</h3>
            {emoticons.length === 0 ? (
              <p className="text-muted-foreground text-sm text-center py-4">
                등록된 이모티콘이 없습니다.
              </p>
            ) : (
              <div className="grid grid-cols-2 gap-2">
                {emoticons.map((emoticon) => (
                  <div
                    key={emoticon.id}
                    className="flex items-center justify-between p-2 bg-card border border-border"
                  >
                    <div className="flex items-center gap-2">
                      <div className="w-8 h-8 relative">
                        <Image
                          src={emoticon.image_url}
                          alt={emoticon.name}
                          fill
                          className="object-contain"
                        />
                      </div>
                      <span className="text-sm font-mono">:{emoticon.name}:</span>
                    </div>
                    <Button
                      variant="destructive"
                      size="icon"
                      className="h-6 w-6"
                      onClick={() => handleDelete(emoticon.id)}
                    >
                      <Trash2 className="h-3 w-3" />
                    </Button>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}
